gPO(){return"\u0628\u0686\u06c6 \u0698\u0648\u0648\u0631\u06d5\u0648\u06d5 \u0628\u06c6 \u062a\u06c6\u0645\u0627\u0631\u06a9\u0631\u062f\u0646\u06cc \u06af\u06d5\u0634\u062a \u0648 \u0628\u06d5\u0695\u06ce\u0648\u06d5\u0628\u0631\u062f\u0646\u06cc \u06af\u06d5\u0634\u062a\u06d5\u06a9\u0627\u0646\u062a."},
