gEC(){return"\u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5 \u062f\u0631\u0648\u0633\u062a\u06a9\u0631\u0627 \u2014 \u0626\u06cc\u0645\u06d5\u06cc\u0644\u06d5\u06a9\u06d5\u062a \u0628\u067e\u0634\u06a9\u0646\u06d5 \u0628\u06c6 \u067e\u0634\u062a\u0695\u0627\u0633\u062a\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u060c \u067e\u0627\u0634\u0627\u0646 \u0628\u0686\u06c6 \u0698\u0648\u0648\u0631\u06d5\u0648\u06d5."},
