gHA(){return"\u0686\u0648\u0648\u0646\u06d5\u0698\u0648\u0648\u0631\u06d5\u0648\u06d5 / \u062f\u0631\u0648\u0633\u062a\u06a9\u0631\u062f\u0646\u06cc \u0647\u06d5\u0698\u0645\u0627\u0631"},
