gHz(){return"\u0648\u0631\u062f\u06d5\u06a9\u0627\u0631\u06cc \u0647\u06d5\u0698\u0645\u0627\u0631"},
gNX(){return"+964 750 000 0000"},
gNY(){return"\u067e\u0627\u0634\u06d5\u06a9\u06d5\u0648\u062a\u06a9\u0631\u062f\u0646\u06cc \u06af\u06c6\u0695\u0627\u0646\u06a9\u0627\u0631\u06cc\u06cc\u06d5\u06a9\u0627\u0646"},
gNZ(){return"\u067e\u0631\u06c6\u0641\u0627\u06cc\u0644\u06d5\u06a9\u06d5 \u0646\u0648\u06ce\u06a9\u0631\u0627\u06cc\u06d5\u0648\u06d5."},
gE6(){return"\u06af\u06c6\u0695\u06cc\u0646\u06cc \u0648\u0634\u06d5\u06cc \u0646\u0647\u06ce\u0646\u06cc"},
gNT(){return"\u0648\u0634\u06d5\u06cc \u0646\u0647\u06ce\u0646\u06cc \u0646\u0648\u06ce"},
gNU(){return"\u0644\u0627\u0646\u06cc\u06a9\u06d5\u0645 \u0666 \u067e\u06cc\u062a"},
gNW(){return"\u0648\u0634\u06d5\u06cc \u0646\u0647\u06ce\u0646\u06cc \u0646\u0648\u06ce\u06a9\u0631\u0627\u06cc\u06d5\u0648\u06d5."},
gNV(){return"\u0648\u0634\u06d5\u06cc \u0646\u0647\u06ce\u0646\u06cc \u062f\u06d5\u0628\u06ce\u062a \u0644\u0627\u0646\u06cc\u06a9\u06d5\u0645 \u0666 \u067e\u06cc\u062a \u0628\u06ce\u062a."},
gNL(){return"\u0646\u0627\u0648\u0686\u06d5\u06cc \u0645\u06d5\u062a\u0631\u0633\u06cc"},
